import React from 'react'
import c from './add.module.scss'
import { InputMask } from '@react-input/mask'

const AddTime = ({ setActive }) => {
  const [time, setTime] = React.useState('')
  const [name, setName] = React.useState('')

  return (
    <div className={c.container}>
      <div className={c.addTime}>
        <h1>Добавить время</h1>
        <div className={c.timeInput}>
          <p>Введите наименование услуги</p>
          <input type="text" onChange={e => setName(e.target.valye)} />
        </div>
        <div className={c.timeInput}>
          <p>Введите время</p>
          <InputMask
            mask="99:99"
            placeholder="00:00"
            className={c.input}
            type="text"
            value={time}
            onChange={e => setTime(e.target.value)}
            replacement={{ 9: /\d/ }} // ✅ это обязательно

          />
        </div>
      </div>
    </div>
  )
}

export default AddTime;
